查看 `src/dashboard/services/iteration.service.ts`，发现所有数据库操作都是**同步**的：

```typescript
// ❌ 当前问题：同步数据库操作会阻塞事件循环
create(dto: CreateIterationDto): Iteration {
  const stmt = this.db.prepare(`INSERT INTO iterations ...`);
  const result = stmt.run(...);  // 阻塞！
  return this.findById(result.lastInsertRowid as number)!;
}

update(id: number, dto: UpdateIterationDto): Iteration | null {
