### 实施方案

#### 方案 A：使用 `better-sqlite3` 的异步封装（推荐）⭐

创建异步包装层：

```typescript
// src/dashboard/services/iteration-async.service.ts
import { Database } from 'better-sqlite3';
import { IterationService } from './iteration.service';

export class AsyncIterationService {
  private iterationService: IterationService;

  constructor(db: Database) {
    this.iterationService = new IterationService(db);
  }

  /**
   * 异步创建迭代 - 不阻塞主线程
   */
  async createAsync(dto: CreateIterationDto): Promise<Iteration> {
    // 使用 setImmediate 避免阻塞
    return new Promise((resolve, reject) => {
      setImmediate(() => {
        try {
          const result = this.iterationService.create(dto);
          resolve(result);
        } catch (error) {
          reject(error);
        }
      });
    });
  }

  /**
   * 异步更新迭代
   */
  async updateAsync(id: number, dto: UpdateIterationDto): Promise<Iteration | null> {
    return new Promise((resolve, reject) => {
      setImmediate(() => {
        try {
          const result = this.iterationService.update(id, dto);
          resolve(result);
        } catch (error) {
          reject(error);
        }
      });
    });
  }

  /**
   * 批量异步更新 - 性能优化
   */
  async batchUpdateAsync(updates: Array<{ id: number; dto: UpdateIterationDto }>): Promise<Iteration[]> {
    return new Promise((resolve, reject) => {
      setImmediate(() => {
        try {
          const results = updates.map(({ id, dto }) => 
            this.iterationService.update(id, dto)
          );
          resolve(results.filter(Boolean) as Iteration[]);
        } catch (error) {
          reject(error);
        }
      });
    });
  }

  // 查询方法保持同步（读操作通常很快）
  findById(id: number): Iteration | null {
    return this.iterationService.findById(id);
  }

  getList(options: ListOptions): PaginatedResult<Iteration> {
    return this.iterationService.getList(options);
  }
}
```

#### 方案 B：使用 `better-sqlite3` + Worker 线程

```typescript
// src/dashboard/services/iteration-worker.service.ts
import { parentPort, workerData } from 'worker_threads';
import Database from 'better-sqlite3';
import { IterationService } from './iteration.service';

if (parentPort) {
  const db = new Database(workerData.dbPath);
  const service = new IterationService(db);

  parentPort.on('message', ({ type, data }) => {
    try {
      switch (type) {
        case 'create':
          parentPort?.postMessage({ 
            success: true, 
            result: service.create(data) 
          });
          break;
        case 'update':
          parentPort?.postMessage({ 
            success: true, 
            result: service.update(data.id, data.dto) 
          });
          break;
      }
    } catch (error) {
      parentPort?.postMessage({ success: false, error });
    }
  });
}
