## ✨ 改进方案

### 改进1: 修复心跳检测内存泄漏

**优先级**: 🔴 **P0** (必须修复)  
**工作量**: 1小时

#### 技术方案

```typescript
export class RealtimeService {
  // 添加超时定时器映射
  private timeoutTimers: Map<WebSocket, NodeJS.Timeout> = new Map();

  private startHeartbeat(client: WSClient): void {
    // 清除旧的定时器
    if (client.pingInterval) {
      clearInterval(client.pingInterval);
    }

    // 清除旧的超时定时器(🆕 修复内存泄漏)
    const oldTimeout = this.timeoutTimers.get(client.socket);
    if (oldTimeout) {
      clearTimeout(oldTimeout);
      this.timeoutTimers.delete(client.socket);
    }

    client.pingInterval = setInterval(() => {
      if (client.socket.readyState === WebSocket.OPEN) {
        try {
          client.socket.send(JSON.stringify({ event: 'ping' }));
          client.lastPing = new Date();

          // 创建新的超时检测并保存引用(🆕 可清理)
          const timeoutId = setTimeout(() => {
            const elapsed = Date.now() - client.lastPing.getTime();
            if (elapsed > this.config.heartbeatTimeout) {
              this.logger.warn({ clientId: client.id, elapsed }, 'Client heartbeat timeout');
              client.socket.terminate();
            }
          }, this.config.heartbeatTimeout);

          // 保存定时器引用
          this.timeoutTimers.set(client.socket, timeoutId);

        } catch (error) {
          this.logger.error({ error, clientId: client.id }, 'Failed to send ping');
        }
      }
    }, this.config.heartbeatInterval);
  }

  removeClient(socket: WebSocket): void {
    const client = this.clients.get(socket);
    if (client) {
      // 停止心跳检测
      if (client.pingInterval) {
        clearInterval(client.pingInterval);
      }

      // 🆕 清理超时定时器
      const timeoutId = this.timeoutTimers.get(socket);
      if (timeoutId) {
        clearTimeout(timeoutId);
        this.timeoutTimers.delete(socket);
      }

      this.logger.info({ clientId: client.id }, 'WebSocket client disconnected');
      this.clients.delete(socket);
    }
  }
}
```

**收益**:
- ✅ 完全消除内存泄漏
- ✅ 长时间运行内存稳定
- ✅ 生产环境可用性提升

