### 改进2: 异步连接清理 + 消息队列

**优先级**: 🟡 **P1** (推荐)  
**工作量**: 2小时

#### 技术方案

```typescript
export class RealtimeService {
  // 🆕 消息队列
  private messageQueue: Array<{ event: WSEvent; timestamp: number }> = [];
  private queueProcessing = false;
  private readonly MAX_QUEUE_SIZE = 1000;
  private readonly QUEUE_BATCH_SIZE = 100;

  /**
   * 🆕 异步清理断开的连接(不阻塞事件循环)
   */
  private async cleanupDeadSockets(deadSockets: WebSocket[]): Promise<void> {
    if (deadSockets.length === 0) return;

    // 使用 setImmediate 异步清理
    setImmediate(() => {
      for (const socket of deadSockets) {
        try {
          this.removeClient(socket);
        } catch (error) {
          this.logger.error({ error }, 'Failed to remove dead socket');
        }
      }
    });
  }

  /**
   * 🆕 添加消息到队列
   */
  enqueue(event: WSEvent): void {
    if (this.messageQueue.length >= this.MAX_QUEUE_SIZE) {
      this.logger.warn('Message queue full, dropping oldest message');
      this.messageQueue.shift(); // 删除最旧的消息
    }

    this.messageQueue.push({ event, timestamp: Date.now() });

    if (!this.queueProcessing) {
      this.processQueue();
    }
  }

  /**
   * 🆕 批量处理消息队列
   */
  private async processQueue(): Promise<void> {
    if (this.queueProcessing) return;

    this.queueProcessing = true;

    while (this.messageQueue.length > 0) {
      // 批量取出消息
      const batch = this.messageQueue.splice(0, this.QUEUE_BATCH_SIZE);

      // 批量发送
      for (const { event } of batch) {
        this.broadcast(event);
      }

      // 让出事件循环控制权
      await new Promise(resolve => setImmediate(resolve));
    }

    this.queueProcessing = false;
  }

  /**
   * 🆕 改进后的广播方法
   */
  broadcast(event: WSEvent): void {
    const data = JSON.stringify(event);
    const deadSockets: WebSocket[] = [];

    // 批量发送
    for (const [socket, client] of this.clients.entries()) {
      try {
        if (socket.readyState === WebSocket.OPEN) {
          socket.send(data);
        } else {
          deadSockets.push(socket);
        }
      } catch (error) {
        this.logger.error({ error, clientId: client.id }, 'Failed to send message');
        deadSockets.push(socket);
      }
    }

    // 🆕 异步清理
    this.cleanupDeadSockets(deadSockets);
  }

  /**
   * 🆕 使用消息队列广播(推荐)
   */
  broadcastQueued(event: WSEvent): void {
    this.enqueue(event);
  }
}
```

**收益**:
- ✅ 不阻塞事件循环
- ✅ 高并发下性能提升
- ✅ 防止消息丢失
- ✅ 支持背压控制

