### 改进3: 消息去重机制

**优先级**: 🟢 **P2** (可选)  
**工作量**: 1.5小时

#### 技术方案

```typescript
export class RealtimeService {
  // 🆕 最近消息缓存(用于去重)
  private recentMessages: Map<string, number> = new Map();
  private readonly DEDUP_WINDOW = 1000; // 1秒去重窗口
  private readonly MAX_RECENT_MESSAGES = 100;

  /**
   * 🆕 生成消息指纹
   */
  private getMessageFingerprint(event: WSEvent): string {
    return `${event.event}:${JSON.stringify(event.data)}`;
  }

  /**
   * 🆕 检查消息是否重复
   */
  private isDuplicate(event: WSEvent): boolean {
    const fingerprint = this.getMessageFingerprint(event);
    const now = Date.now();
    const timestamp = this.recentMessages.get(fingerprint);

    if (timestamp && (now - timestamp) < this.DEDUP_WINDOW) {
      return true; // 重复消息
    }

    // 记录新消息
    this.recentMessages.set(fingerprint, now);

    // 清理过期记录
    if (this.recentMessages.size > this.MAX_RECENT_MESSAGES) {
      const oldestKey = this.recentMessages.keys().next().value;
      this.recentMessages.delete(oldestKey);
    }

    return false;
  }

  /**
   * 🆕 改进的广播方法(带去重)
   */
  broadcastWithDedup(event: WSEvent): void {
    // 检查重复
    if (this.isDuplicate(event)) {
      this.logger.debug({ event: event.event }, 'Duplicate message skipped');
      return;
    }

    // 广播
    this.broadcast(event);
  }
}
```

**收益**:
- ✅ 避免重复消息
- ✅ 节省带宽
- ✅ 提升用户体验

